content:
{
  "schemaVersion": 3,
  "judgeId": "judge_2",
  "comparisons": [
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c2_bamboo_traps",
      "winnerId": "c1_bycatch_ice",
      "reason": "c1 có cơ chế bảo quản bằng bèo tây và lá chuối rất sáng tạo, giải quyết đúng điểm nghẽn thiếu đá lạnh năm 1988, trong khi c2 là kỹ thuật đan bẫy khá phổ biến, ít đột phá về mặt logistics."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c3_sun_drying_fish",
      "winnerId": "c1_bycatch_ice",
      "reason": "c1 tạo ra dòng tiền và kết quả bữa cơm ngay chương 3 thông qua việc cứu mẻ cá dạt, phù hợp với yêu cầu 'thành quả sớm' hơn là quy trình phơi cá mất nhiều thời gian của c3."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c4_rock_pool_tides",
      "winnerId": "c1_bycatch_ice",
      "reason": "c1 có khả năng mở rộng quy mô (scalability) tốt hơn thông qua việc thu mua và bảo quản, trong khi c4 phụ thuộc quá nhiều vào thể lực cá nhân và khai thác thủ công khó bền vững."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c5_shrimp_paste",
      "winnerId": "c1_bycatch_ice",
      "reason": "Cả hai đều tốt về mặt kinh tế, nhưng c1 gắn liền với nhịp sống bến cá và giải quyết vấn đề hao hụt hải sản tươi - một domain opportunity đặc trưng hơn của thập niên 80."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c6_handline_bait",
      "winnerId": "c1_bycatch_ice",
      "reason": "c6 dựa vào 'mồi đặc chế' hơi mang hơi hướng công thức bí mật, trong khi c1 dựa vào tối ưu hóa vật liệu tự nhiên (bèo tây) mang tính thực tế và agency cao hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c7_live_seafood_transport",
      "winnerId": "c1_bycatch_ice",
      "reason": "c7 rất xuất sắc về kỹ thuật cơ khí, nhưng c1 có sự kết nối tình thân và bữa cơm gia đình (chương 3) ấm áp, đúng gu 'gia đình ấm lên từng bước' của độc giả Việt hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c8_light_luring_squid",
      "winnerId": "c1_bycatch_ice",
      "reason": "c8 đối mặt với rủi ro khan hiếm dầu hỏa thời bao cấp/đổi mới, khởi đầu có phần mạo hiểm hơn là cách tận dụng phế phẩm nông nghiệp của c1."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c1_bycatch_ice",
      "reason": "c9 vi phạm yêu cầu về thời gian có thành quả (hàu lớn mất nhiều tháng), trong khi c1 hoàn thành vòng lặp thưởng ngay trong 3 chương đầu."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c10_net_modifications",
      "winnerId": "c1_bycatch_ice",
      "reason": "c10 tập trung vào dịch vụ sửa chữa, nhịp truyện sẽ chậm hơn việc trực tiếp tham gia vào thị trường hàng hóa hải sản sôi động như c1."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_01",
      "winnerId": "c1_bycatch_ice",
      "reason": "c1 có cơ chế kỹ thuật bảo quản rõ ràng hơn concept 01 (vốn thiên về nấu nướng), tạo ra cảm giác 'làm giàu bằng tay nghề' biển đặc sắc hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_02",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 02 về mắm có thời gian ủ lâu, khó kích hoạt 'tiền tươi' ở chương 3 như c1. c1 cũng xử lý tốt hơn vấn đề giới hạn nguồn lợi ở chương 21-30."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_03",
      "winnerId": "c1_bycatch_ice",
      "reason": "c1 có sự chủ động trong việc đi biển và giao thương, trong khi concept 03 thiên về hậu cần, ít tính 'khoái hoạt' của người từng trải làm lại cuộc đời hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_04",
      "winnerId": "c1_bycatch_ice",
      "reason": "Rong biển trong concept 04 khó tạo ra giá trị kinh tế bùng nổ và uy tín nhanh chóng trong bối cảnh năm 1988 so với mặt hàng cá tươi của c1."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_05",
      "winnerId": "c1_bycatch_ice",
      "reason": "Cùng giải quyết vấn đề lạnh, nhưng c1 dùng 'bèo tây' là một chi tiết cực kỳ đắt giá, mang đậm chất Việt Nam và tính agency của nhân vật chính hơn là xây hầm trấu chung chung."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_06",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 06 về đóng tàu đòi hỏi vốn và thời gian lớn, không phù hợp với yêu cầu 'gia đình ấm lên từng bước' và 'khó khăn ngắn' như c1."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_07",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 07 thiên về marketing, trong khi c1 tập trung vào giải quyết hao hụt thực tế tại bến cá, khớp với domain opportunity về phân loại và đá lạnh hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_08",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 08 dựa vào việc 'nhớ vị trí' bãi sò, có phần giống 'kho báu' hơn là dùng năng lực xử lý hàng hóa như c1."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_09",
      "winnerId": "c1_bycatch_ice",
      "reason": "Nghề muối trong concept 09 rất cực nhọc và chậm thu lời, không mang lại cảm giác 'khoái hoạt' và 'thành quả sớm' bằng việc đi buôn cá dạt của c1."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_10",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 10 về du lịch hoàn toàn lạc quẻ với bối cảnh kinh tế năm 1988 và yêu cầu về làm giàu bằng tay nghề biển."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "c5_shrimp_paste",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 có cơ chế 'sục khí bằng bơm xe đạp' rất độc đáo, thể hiện agency mạnh mẽ của nhân vật trong việc biến đồ phế liệu thành công cụ kiếm tiền."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "c10_net_modifications",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 tạo ra giá trị thặng dư cực lớn từ việc giữ sống hải sản, phù hợp với nhịp đọc 'có thành quả sớm' và 'làm giàu nhanh' hơn việc vá lưới."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c3_sun_drying_fish",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 thông minh ở chỗ chọn 'mắm xổi' để xoay vòng vốn nhanh, giải quyết bài toán kinh tế của nhân vật chính tốt hơn quy trình phơi cá phụ thuộc thời tiết của c3."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_03",
      "winnerId": "c10_net_modifications",
      "reason": "c10 có các chi tiết kỹ thuật như 'túi ảo', 'nút thắt kép' và lộ trình 30 chương rõ ràng hơn so với concept 03 còn chung chung."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c4_rock_pool_tides",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 có tính 'nghề' rõ rệt qua việc đan lồng, dễ phát triển thành quy mô tổ đội hơn là việc đi nhặt lộc biển đơn lẻ của c4."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "c6_handline_bait",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8 sử dụng kiến thức quang học để cải tiến đèn măng xông, một hành động chủ động và có tính kỹ thuật cao hơn việc pha trộn mồi câu của c6."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c7_live_seafood_transport",
      "winnerId": "c1_bycatch_ice",
      "reason": "Mặc dù c7 rất hay về kỹ thuật, c1 thắng nhờ sự cân bằng giữa kỹ thuật bảo quản và yếu tố gia đình, bữa cơm, đúng tinh thần 'niên đại văn' Việt Nam hơn."
    }
  ]
}
